const body = $input.first().json.body || $input.first().json;
const { service, property_size, property_type, address, frequency, customer_name, email, phone, notes } = body;
return [{ json: { service: service || 'lawn-mowing', property_size: property_size || 'medium', property_type: property_type || 'residential', address: address || 'Madison WI', frequency: frequency || 'weekly', customer_name: customer_name || '', email: email || '', phone: phone || '', notes: notes || '' } }];

const response = $input.first().json;
const text = response.content?.[0]?.text || '{}';
let quote = {};
try { quote = JSON.parse(text.match(/\{[\s\S]*\}/)?.[0] || '{}'); } catch(e) { quote = { line_items: [], total_low: 0, total_high: 0, notes: 'Quote generation error — contact us for manual estimate.' }; }
const input = $('Parse Quote Request').first().json;
const quote_id = 'TG-Q-' + Date.now();
return [{ json: { quote_id, ...input, quote, generated_at: new Date().toISOString() } }];
